<script setup lang="ts">
import { computed, ref } from 'vue'
import AffiliateMePayoutHistoryTable from './widgets/AffiliateMePayoutHistoryTable.vue'
import { useAffiliateMe } from './composables/useAffiliateMe'

const {
    payoutRows,
    payoutPagination,
    isLoadingPayoutHistory,
    fetchPayoutHistory,
    setPayoutPage,
    setPayoutPerPage,
    setPayoutDateRange,
} = useAffiliateMe()

const fromDate = ref<Date | null>(null)
const toDate = ref<Date | null>(null)

const dateRangeError = computed(() => {
    if (!fromDate.value || !toDate.value) return ''
    if (fromDate.value.getTime() > toDate.value.getTime()) {
        return '開始日期不可晚於結束日期'
    }
    return ''
})

const onSearch = () => {
    if (dateRangeError.value) return
    setPayoutDateRange(fromDate.value, toDate.value)
    fetchPayoutHistory()
}
</script>

<template>
    <h1 class="page-title">撥款歷史紀錄</h1>

    <VaCard>
        <VaCardContent>
            <div class="flex flex-col md:flex-row gap-2 mb-4 items-start md:items-end">
                <VaDateInput v-model="fromDate" label="開始日期" class="w-full md:w-60" clearable />
                <VaDateInput v-model="toDate" label="結束日期" class="w-full md:w-60" clearable />
                <VaButton :disabled="!!dateRangeError" @click="onSearch">搜尋</VaButton>
            </div>

            <VaAlert v-if="dateRangeError" color="danger" class="mb-4" outline>
                {{ dateRangeError }}
            </VaAlert>

            <AffiliateMePayoutHistoryTable
                :rows="payoutRows"
                :pagination="payoutPagination"
                :loading="isLoadingPayoutHistory"
                @update:page="setPayoutPage"
                @update:perPage="setPayoutPerPage"
            />
        </VaCardContent>
    </VaCard>
</template>
