<script setup lang="ts">
import { defineVaDataTableColumns } from 'vuestic-ui'
import { computed, PropType } from 'vue'
import { useFormat } from '../../../composables/useFormat'
import { Pagination } from '../composables/useAffiliateMe'
import { AffiliateMePayoutHistoryRow } from '../types'

const columns = defineVaDataTableColumns([
    { label: '撥款日期', key: 'payoutDate' },
    { label: '撥款金額', key: 'amount' },
    { label: '備註', key: 'note' },
])

const props = defineProps({
    rows: {
        type: Array as PropType<AffiliateMePayoutHistoryRow[]>,
        required: true,
    },
    loading: { type: Boolean, default: false },
    pagination: { type: Object as PropType<Pagination>, required: true },
})

const emit = defineEmits<{
    (event: 'update:page', page: number): void
    (event: 'update:perPage', perPage: number): void
}>()

const { formatDateTime } = useFormat()

const formatPayoutDate = (value: string): string => {
    if (!value) return '-'

    const parsedNumber = Number(value)
    if (Number.isFinite(parsedNumber) && parsedNumber > 0) {
        return formatDateTime(parsedNumber)
    }

    const parsedIso = Date.parse(value)
    if (Number.isFinite(parsedIso)) {
        return formatDateTime(parsedIso)
    }

    return value
}

const totalPages = computed(() => Math.ceil(props.pagination.total / props.pagination.perPage))
</script>

<template>
    <VaDataTable :columns="columns" :items="rows" :loading="$props.loading">
        <template #cell(payoutDate)="{ rowData }">
            {{ formatPayoutDate(rowData.payoutDate) }}
        </template>

        <template #cell(amount)="{ rowData }">
            <span class="font-semibold text-success">VND {{ Number(rowData.amount).toLocaleString() }}</span>
        </template>

        <template #cell(note)="{ rowData }">
            <span>{{ rowData.note || '-' }}</span>
        </template>
    </VaDataTable>

    <VaAlert v-if="!$props.loading && rows.length === 0" color="secondary" class="mt-4" outline>
        目前尚無撥款紀錄
    </VaAlert>

    <div class="flex flex-col-reverse md:flex-row gap-2 justify-between items-center py-2 mt-2">
        <div>
            <b>{{ $props.pagination.total }} results.</b>
            Results per page
            <VaSelect
                :model-value="$props.pagination.perPage"
                class="!w-20"
                :options="[10, 50, 100]"
                @update:modelValue="(value) => emit('update:perPage', Number(value))"
            />
        </div>

        <div v-if="totalPages > 1" class="flex">
            <VaButton
                preset="secondary"
                icon="va-arrow-left"
                aria-label="Previous page"
                :disabled="$props.pagination.page === 1"
                @click="emit('update:page', $props.pagination.page - 1)"
            />
            <VaButton
                class="mr-2"
                preset="secondary"
                icon="va-arrow-right"
                aria-label="Next page"
                :disabled="$props.pagination.page === totalPages"
                @click="emit('update:page', $props.pagination.page + 1)"
            />
            <VaPagination
                :model-value="$props.pagination.page"
                buttons-preset="secondary"
                :pages="totalPages"
                :visible-pages="5"
                :boundary-links="false"
                :direction-links="false"
                @update:modelValue="(value) => emit('update:page', Number(value))"
            />
        </div>
    </div>
</template>
